mapper.update:
update lc_checkin_apply
apply_no = #{applyNo}, apply_user_id = #{applyUserId}, apply_user_name = #{applyUserName}, apply_status = #{applyStatus}, process_instance_id = #{processInstanceId}, reject_reason = #{rejectReason}, del_flag = #{delFlag}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime},
where apply_id = #{applyId}

mapper.select:
SELECT a.apply_id AS applyId, a.apply_no AS applyNo, b.elderly_name AS elderlyName, b.id_card AS idCard, e.bed_no AS bedNo, a.create_time AS createTime, a.apply_user_name AS createBy, f.checkin_time AS checkinTime, -- 详情页扩展字段 b.phone AS phone, b.gender AS gender, b.age AS age, e.care_fee AS careFee, e.room_fee AS roomFee, e.total_fee AS totalFee, f.contract_no AS contractNo, f.sign_time AS signTime, f.pay_status AS payStatus FROM lc_checkin_apply a LEFT JOIN lc_checkin_basic b ON a.apply_id = b.apply_id AND b.del_flag = '0' LEFT JOIN lc_checkin_config e ON a.apply_id = e.apply_id AND e.del_flag = '0' LEFT JOIN lc_checkin_contract f ON a.apply_id = f.apply_id AND f.del_flag = '0' WHERE a.del_flag = '0' -- 原型核心规则：仅展示已审批通过/已入住数据 AND a.apply_status = '09' -- 精准搜索：单据编号
AND a.apply_no = #{apply.applyNo}
-- 精准搜索：身份证号
AND b.id_card = #{apply.idCard}
-- 模糊搜索：老人姓名
AND b.elderly_name LIKE CONCAT('%', #{apply.elderlyName}, '%')
-- 日期范围：入住日期
AND f.checkin_time >= #{beginTime}
AND f.checkin_time <= #{endTime}
ORDER BY a.create_time DESC
